import{_ as s,C as p,o as e,c as r,a2 as l,E as i}from"./chunks/framework.30PL1Nye.js";const t="/assets/spring-framework.Dae2GPtR.png",o="/assets/diagram-boot-reactor.D1OwXv5q.svg",g="/assets/springboot-gradle-project.Z4jYc9vQ.png",c="/assets/webproject-helloworld.Dm-BICeB.png",w=JSON.parse('{"title":"从零开始入门 Spring Boot 框架","description":"","frontmatter":{"sidebar":"auto","comment":"getting-started-spring-boot-framework"},"headers":[],"relativePath":"blog/getting-started-from-scratch-spring-boot-framework.md","filePath":"blog/getting-started-from-scratch-spring-boot-framework.md"}'),d={name:"blog/getting-started-from-scratch-spring-boot-framework.md"};function u(h,a,b,m,S,f){const n=p("site-footer");return e(),r("div",null,[a[0]||(a[0]=l('<h1 id="从零开始入门-spring-boot-框架" tabindex="-1">从零开始入门 Spring Boot 框架 <a class="header-anchor" href="#从零开始入门-spring-boot-框架" aria-label="Permalink to &quot;从零开始入门 Spring Boot 框架&quot;">​</a></h1><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>近期开始筹备小程序开发运营平台，之前使用 Egg.js 构建过后台管理系统，但是在市场推广过程中发现会使用 Node.js 服务的人员真的很少，前端人员不太懂数据库库表设计，传统后端对于 Node.js 服务又不太熟悉，所以实际场景中对于团队人员配置很尴尬。基于公司产品大多数是 Java 技术体系的考虑，所以决定在新项目中采用 Java 社区的框架去构建。JavaEE 常见的框架组合有 SSH(Structs + Spring + Hibernate)和 SSM(Spring + SpringMVC + MyBatis)，一般学习顺序是 Servlet -&gt; JSP -&gt; Spring -&gt; 组合框架，传统的 Spring 项目开发上手难度较大，所以项目计划采用 Spring Boot 框架。</p><h2 id="为什么要学习-spring-boot" tabindex="-1">为什么要学习 Spring Boot？ <a class="header-anchor" href="#为什么要学习-spring-boot" aria-label="Permalink to &quot;为什么要学习 Spring Boot？&quot;">​</a></h2><h3 id="spring-framework-5" tabindex="-1">Spring Framework 5 <a class="header-anchor" href="#spring-framework-5" aria-label="Permalink to &quot;Spring Framework 5&quot;">​</a></h3><p>Spring Framework 5 是一个重要的版本，距离 Spring Framework 4 差不多四年。在此期间，大多数增强都是在 Spring Boot 项目中完成的。Spring5 发行版中的一些特性：</p><ul><li>基准升级</li></ul><p>要构建和运行 Spring5 应用程序，你至少需要 J2EE7 和 JDK8。以前的 JDK 和 JavaEE 版本不再支持。 JavaEE7 包含：Servlet 3.1、JMS 2.0、JPA 2.1、JAX-RS 2.0、Bean Validation 1.1。 各种服务器最低支持版本：Tomcat 8.5+、Jetty 9.4+、WildFly 10+、Netty 4.1+、Undertow 1.4+。</p><ul><li>兼容 JDK9 运行时</li></ul><p>Spring5 发行版与 JDK9 发行日期非常接近。目标是让 Spring Framework5 在 JDK9 的 GA 之后正确运行。 Spring5 版本的候选版本已经在 classpath 和 modulepath 上支持 Java9 了。</p><ul><li>使用 JDK8 特性</li></ul><p>在 Spring4.3 之前，JDK 基准版本是 6。所以 Spring4 必须支持 Java6,7 和 8，为了保持向后兼容性， Spring 框架没有适应 Java8 带来的许多新特性，比如 lambda 表达式。Spring5 的基准版本为 8，因此它使用了 Java8 和 9 的许多新特性。例如： Spring 接口中的默认方法 基于 Java8 反射增强的内部代码改进 在框架代码中使用函数式编程 - lambda 表达式 和 stream 流。</p><ul><li>响应式编程支持</li></ul><p>响应式编程是 Spring Framework 5.0 最重要的特性之一。响应式编程提供了另一种编程风格，专注于构建对事件做出响应的应用程序。 Spring Framework 5.0 包含响应流（定义响应性 API 的语言中立尝试）和 Reactor（由 Spring Pivotal 团队提供的 Reactive Stream 的 Java 实现），以用于其自身的用途以及其许多核心 API。</p><p>Spring Web Reactive 在 spring-webmvc 模块中现有的（而且很流行）Spring Web MVC 旁边的新的 spring-web-reactive 模块中。 请注意，在 Spring5 中，传统的 SpringMVC 支持 Servlet3.1 上运行，或者支持 JavaEE7 的服务器。</p><ul><li>函数式 web 框架</li></ul><p>除了响应式功能之外，Spring5 还提供了一个函数式 Web 框架。它提供了使用函数式编程风格来定义端点的特性。 该框架引入了两个基本组件：HandlerFunction 和 RouterFunction。HandlerFunction 表示处理接收到的请求并生成响应的函数。 RouterFunction 替代了 @RequestMapping 注解。它用于将接收到的请求路由到处理函数。</p><ul><li>Kotlin 支持</li></ul><p>Kotlin 是一种静态类型的 JVM 语言，它让代码具有表现力，简洁性和可读性。 Spring5.0 对 Kotlin 有很好的支持。</p><h3 id="spring-boot-2" tabindex="-1">Spring Boot 2 <a class="header-anchor" href="#spring-boot-2" aria-label="Permalink to &quot;Spring Boot 2&quot;">​</a></h3><p>Spring 框架是 Java EE 中最常用的框架，主要包含的内容有：</p><p><img src="'+t+'" alt=""></p><ul><li><strong>Spring Boot</strong>：Spring Boot 旨在尽可能快地启动和运行，只需最少的 Spring 前端配置。 Spring Boot 对构建生产就绪应用程序持批评态度。</li><li><strong>Spring Cloud</strong>：Spring Cloud 直接基于 Spring Boot 的创新企业 Java 方法，通过实施经过验证的模式，为您的微服务带来弹性，可靠性和协调，从而简化了分布式微服务式架构。</li><li><strong>Spring Cloud Data Flow</strong>：将企业连接到任何东西 - 移动设备，传感器，可穿戴设备，汽车等。Spring Cloud Data Flow 为创建可组合数据微服务提供统一服务，这些服务可解决基于流和基于 ETL 的数据处理模式。</li></ul><p>Spring Boot 2.0 基于 Spring 5 Framework ，提供了异步非阻塞 IO 的响应式 Stream 、非堵塞的函数式 Reactive Web 框架 Spring WebFlux。</p><p><img src="'+o+'" alt=""></p><h3 id="spring-boot-优点" tabindex="-1">Spring Boot 优点 <a class="header-anchor" href="#spring-boot-优点" aria-label="Permalink to &quot;Spring Boot 优点&quot;">​</a></h3><ul><li>使用 Spring 项目引导页面可以在几秒构建一个项目</li><li>方便对外输出各种形式的服务，如 RESTAPI、WebSocket、Web、Streaming、Tasks</li><li>非常简洁的安全策略集成</li><li>支持关系数据库和非关系数据库</li><li>支持运行期内嵌容器，如 Tomcat、Jetty、Undertow</li><li>强大的开发包，支持热启动</li><li>自动管理依赖</li><li>自带应用监控</li><li>支持各种 IDE，如 IntelliJ IDEA 、NetBeans、Eclipse 等</li></ul><p>Spring Boot 三大特性：</p><ul><li>组件自动装配：Web MVC、Web Flux、JDBC 等</li><li>嵌入式 Web 容器：Tomcat、Jetty 以及 Undertow</li><li>生产准备特性：指标、健康检查、外部化配置等</li></ul><h3 id="社区资源" tabindex="-1">社区资源 <a class="header-anchor" href="#社区资源" aria-label="Permalink to &quot;社区资源&quot;">​</a></h3><ul><li><a href="https://springcloud.cc/" target="_blank" rel="noreferrer">Spring Cloud 中文网</a></li><li><a href="http://www.springcloud.cn/" target="_blank" rel="noreferrer">Spring Cloud 中国社区</a></li><li><a href="https://spring.io/projects/spring-boot" target="_blank" rel="noreferrer">Spring Boot 官方文档</a></li><li><a href="http://springboot.fun/" target="_blank" rel="noreferrer">Spring Boot 中文索引</a></li><li><a href="http://www.spring4all.com/" target="_blank" rel="noreferrer">Spring For All 垂直技术社区</a></li></ul><h2 id="国际惯例-hello-world-工程" tabindex="-1">国际惯例 Hello, world 工程 <a class="header-anchor" href="#国际惯例-hello-world-工程" aria-label="Permalink to &quot;国际惯例 Hello, world 工程&quot;">​</a></h2><h3 id="创建工程" tabindex="-1">创建工程 <a class="header-anchor" href="#创建工程" aria-label="Permalink to &quot;创建工程&quot;">​</a></h3><ul><li>在线创建工程模块：通过 start.spring.io 网站 SpringInitializr 创建：<a href="https://start.spring.io/" target="_blank" rel="noreferrer">https://start.spring.io/</a></li><li>通过 IDEA 开发工程创建：IDEA 企业版可以通过 spring Initializr 创建，社区版可以下载 Spring Assistant 插件。</li></ul><p>这里我下载的是 IDEA 社区版，通过下载 Spring Assistant 插件实现工程创建，下面是创建一个基本的 Web 工程：</p><p>我们可以选择 Maven 或者 Gradle 管理我们的依赖，这里选择 Gradle： <img src="'+g+'" alt="选择 Gradle 工程"></p><p>我们可以配置工程的依赖： <img src="'+c+`" alt="选择 Web 工程"></p><h3 id="工程介绍" tabindex="-1">工程介绍 <a class="header-anchor" href="#工程介绍" aria-label="Permalink to &quot;工程介绍&quot;">​</a></h3><p>Spring Boot Gradle 工程基本结构为：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─gradle</span></span>
<span class="line"><span>│  └─wrapper</span></span>
<span class="line"><span>├─src</span></span>
<span class="line"><span>│  ├─main</span></span>
<span class="line"><span>|  |  ├─java</span></span>
<span class="line"><span>|  |  └─resources</span></span>
<span class="line"><span>│  └─test</span></span>
<span class="line"><span>├─build.gradle</span></span>
<span class="line"><span>├─gradlew</span></span>
<span class="line"><span>├─gradlew.bat</span></span>
<span class="line"><span>└─settings.gradle</span></span></code></pre></div><p>build.gradle 文件中的 dependencies 中添加 springboot 框架的 web 依赖：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>implementation &#39;org.springframework.boot:spring-boot-starter-web&#39;</span></span></code></pre></div><p>典型的 build.gradle 脚本如下：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>apply plugin: &#39;org.springframework.boot&#39;</span></span>
<span class="line"><span>apply plugin: &#39;io.spring.dependency-management&#39;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>buildscript {</span></span>
<span class="line"><span>	repositories {</span></span>
<span class="line"><span>		jcenter()</span></span>
<span class="line"><span>		mavenCentral()</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>	dependencies {</span></span>
<span class="line"><span>		classpath(&quot;org.springframework.boot:spring-boot-gradle-plugin:2.1.3.RELEASE&quot;)</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>repositories {</span></span>
<span class="line"><span>	jcenter()</span></span>
<span class="line"><span>	mavenCentral()</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>bootJar {</span></span>
<span class="line"><span>	baseName = &#39;helloworld&#39;</span></span>
<span class="line"><span>	version =  &#39;0.1.0&#39;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>sourceCompatibility = 1.8</span></span>
<span class="line"><span>targetCompatibility = 1.8</span></span>
<span class="line"><span></span></span>
<span class="line"><span>dependencies {</span></span>
<span class="line"><span>	implementation &quot;org.springframework.boot:spring-boot-starter-web&quot;</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>工程整体上和 Android 工程类似，同样也可以采用多 Module 的构建模式，具体多配置可以参考 <a href="https://docs.gradle.org" target="_blank" rel="noreferrer">Gradle 官方文档</a>。</p><h3 id="创建自定义-controller-类" tabindex="-1">创建自定义 Controller 类 <a class="header-anchor" href="#创建自定义-controller-类" aria-label="Permalink to &quot;创建自定义 Controller 类&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>package cn.com.agree.helloworld;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>import org.springframework.boot.autoconfigure.EnableAutoConfiguration;</span></span>
<span class="line"><span>import org.springframework.stereotype.Controller;</span></span>
<span class="line"><span>import org.springframework.web.bind.annotation.RequestMapping;</span></span>
<span class="line"><span>import org.springframework.web.bind.annotation.ResponseBody;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>@Controller</span></span>
<span class="line"><span>@EnableAutoConfiguration</span></span>
<span class="line"><span>class HelloworldController {</span></span>
<span class="line"><span>    @ResponseBody</span></span>
<span class="line"><span>    @RequestMapping(&quot;/&quot;)</span></span>
<span class="line"><span>    public String home() {</span></span>
<span class="line"><span>        return &quot;Hello, World&quot;;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>在 Application 类处右键-执行 run 即可，此时不需要管存不存在 web.xml, 也不需要创建 application.properties 文件。打开 <a href="http://localhost:8080/" target="_blank" rel="noreferrer">http://localhost:8080/</a> 会出现 <code>Hello, World</code>。</p><blockquote><p>组件自动装配：</p><ul><li>激活：@EnableAutoConfiguration</li><li>配置：/META-INF/spring.factories</li><li>实现：XXXAutoConfiguration</li></ul></blockquote><p>其实我们也可以在 Application 类填加 @Controller、@RequestMapping 注解实现上述功能。</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="http://www.cnblogs.com/skyme/p/8976866.html" target="_blank" rel="noreferrer">微服务系列教程</a></li></ul>`,52)),i(n)])}const v=s(d,[["render",u]]);export{w as __pageData,v as default};
